/// <summary>
/// Tarefa #28 — implementado por qualquer componente do player que conceda
/// resistência adicional a knockback enquanto activo (ex: habilidade "Coala
/// agarrado" a um tronco/parede). <see cref="PlayerCombat.ComputeKnockbackMultiplier"/>
/// multiplica o resultado de todos os providers presentes no player.
///
/// Um valor de 0 concede IMUNIDADE TOTAL a knockback (ignora o limite mínimo
/// configurado em <see cref="PlayerCombat"/>); valores entre 0 e 1 reduzem o
/// knockback proporcionalmente; 1 = sem efeito.
/// </summary>
public interface IKnockbackResistanceProvider
{
    /// <summary>Multiplicador de knockback (1 = normal, 0 = imunidade total) enquanto este provider estiver activo.</summary>
    float KnockbackMultiplier { get; }
}
